    /**
     * SECURITY: Validates filename against injection and traversal attacks.
     * Uses an allowlist approach for characters and extensions.
     * 
     * @return null if valid, error description if invalid
     */
    static String validateFilename(String filename) {
        if (filename == null || filename.isBlank()) {
            return "Filename is empty";
        }

        if (filename.length() > MAX_FILENAME_LENGTH) {
            return "Filename too long";
        }

        // SECURITY: Reject path traversal attempts
        if (filename.contains("..") || filename.contains("/") || filename.contains("\\")) {
            return "Path traversal characters not allowed";
        }

        // SECURITY: Reject null bytes (can bypass path checks in some systems)
        if (filename.contains("\0")) {
            return "Null bytes not allowed";
        }

        // SECURITY: Only allow alphanumeric, hyphens, underscores, dots
        if (!filename.matches("^[a-zA-Z0-9][a-zA-Z0-9._\\-]*$")) {
            return "Filename contains disallowed characters";
        }

        // SECURITY: Reject hidden files (starting with dot)
        if (filename.startsWith(".")) {
            return "Hidden files not allowed";
        }

        // SECURITY: Validate file extension against allowlist
        String extension = getFileExtension(filename);
        if (extension == null || !ALLOWED_EXTENSIONS.contains(extension.toLowerCase())) {
            return "File extension not in allowlist: " + ALLOWED_EXTENSIONS;
        }

        return null; // valid
    }

    /**
     * SECURITY: Resolves a filename to an absolute path and verifies it's within
     * the allowed upload directory. Prevents directory traversal.
     */
    static Path resolveAndValidatePath(String filename) {
        try {
            Path resolved = UPLOAD_BASE_DIR.resolve(filename).toAbsolutePath().normalize();

            // SECURITY: Verify the resolved path is still within the allowed directory
            if (!resolved.startsWith(UPLOAD_BASE_DIR)) {
                logger.warning("Path traversal attempt detected: " + sanitizeForLog(filename));
                return null;
            }

            return resolved;
        } catch (Exception e) {
            logger.warning("Path resolution failed for: " + sanitizeForLog(filename));
            return null;
        }
    }

    static String getFileExtension(String filename) {
        int lastDot = filename.lastIndexOf('.');
        if (lastDot < 0 || lastDot == filename.length() - 1) {
            return null;
        }
        return filename.substring(lastDot);
    }

    static String computeSha256Hex(byte[] data) {
        try {
            MessageDigest digest = MessageDigest.getInstance("SHA-256");
            return bytesToHex(digest.digest(data));
        } catch (NoSuchAlgorithmException e) {
            throw new RuntimeException("SHA-256 not available", e);
        }
    }

    static String bytesToHex(byte[] bytes) {
        StringBuilder sb = new StringBuilder(bytes.length * 2);
        for (byte b : bytes) {
            sb.append(String.format("%02x", b));
        }
        return sb.toString();
    }

    /**
     * SECURITY: Sanitize strings before logging to prevent log injection.
     */
    static String sanitizeForLog(String input) {
        if (input == null) return "null";
        // Remove newlines, carriage returns, and control characters
        return input.replaceAll("[\\r\\n\\t]", "_")
                .replaceAll("[^\\x20-\\x7E]", "?")
                .substring(0, Math.min(input.length(), 200));
    }

